#!/usr/bin/env python3
"""ShowingTime PDF import on main Activities page"""
import base64, os, sys
if not os.path.exists("frontend/src/pages"):
    print("Error: Run from ~/seller-portal"); sys.exit(1)
content = base64.b64decode("")
with open("frontend/src/pages/AdminActivities.jsx", "wb") as f:
    f.write(content)
print(f"  Updated: AdminActivities.jsx ({len(content):,} bytes)")
print("\nNow run:")
print('  git add -A && git commit -m "ShowingTime import on main Activities page" && git push')
